import json
import sys
from typing import Dict, List, Any

def dump_dict_to_json(data_dict, filename, indent=4, ensure_ascii=False):
    """
    Dump dictionary to JSON file
    
    Parameters:
    data_dict: Dictionary to dump
    filename: Output filename
    indent: JSON formatting indentation (default 4 spaces)
    ensure_ascii: Whether to ensure ASCII encoding (default False, supports Chinese)
    """
    try:
        with open(filename, 'w', encoding='utf-8') as f:
            json.dump(data_dict, f, indent=indent, ensure_ascii=ensure_ascii)
        print(f"Dictionary successfully dumped to {filename}")
    except Exception as e:
        print(f"Dump failed: {e}")

def load_json_file(filename: str) -> Dict[str, Any]:
    """Load JSON file"""
    try:
        with open(filename, 'r', encoding='utf-8') as f:
            return json.load(f)
    except FileNotFoundError:
        print(f"Error: File not found {filename}")
        sys.exit(1)
    except json.JSONDecodeError as e:
        print(f"Error: {filename} is not a valid JSON file: {e}")
        sys.exit(1)

def extract_node_count(instance_name):
    """Extract number of points from instance name"""
    try:
        import re
        match = re.search(r'X-n(\d+)-k\d+', instance_name)
        if match:
            return int(match.group(1))
        return 0
    except:
        return 0

def compare_gaps(hgs_file: str, llm_file: str) -> None:
    """
    Compare gap values of two JSON files
    Calculation method: (hgs_gap - llm_gap) / llm_gap * 100%
    """
    print(f"Comparing {hgs_file} and {llm_file}...")
    
    # Load two JSON files
    hgs_data = load_json_file(hgs_file)
    llm_data = load_json_file(llm_file)
    
    # Check if all_costs is included
    if 'all_costs' not in hgs_data:
        print(f"Error: 'all_costs' field not found in {hgs_file}")
        return
    
    if 'all_costs' not in llm_data:
        print(f"Error: 'all_costs' field not found in {llm_file}")
        return
    
    hgs_costs = hgs_data['all_costs']
    llm_costs = llm_data['all_costs']
    
    # Create mapping from instance name to gap value and time
    hgs_gaps = {item['instance_name']: item['gap'] for item in hgs_costs}
    llm_gaps = {item['instance_name']: item['gap'] for item in llm_costs}
    
    # Extract time information (if exists)
    hgs_times = {item['instance_name']: item.get('time', None) for item in hgs_costs}
    llm_times = {item['instance_name']: item.get('time', None) for item in llm_costs}
    
    # Find common instances
    common_instances = set(hgs_gaps.keys()) & set(llm_gaps.keys())
    
    if not common_instances:
        print("Error: no common instances found in the two files")
        return
    
    print(f"\nFound {len(common_instances)} common instance(s)")
    print("=" * 80)
    
    # Sort by node count (descending)
    sorted_instances = sorted(common_instances, key=extract_node_count, reverse=True)
    
    # Compute improvement for each instance
    improvements = []
    detailed_results = []
    
    for instance in sorted_instances:
        hgs_gap = hgs_gaps[instance]
        llm_gap = llm_gaps[instance]
        hgs_time = hgs_times[instance]
        llm_time = llm_times[instance]
        
        # # Alternative: improvement = (hgs_gap - llm_gap) / llm_gap * 100%
        # if llm_gap != 0:
        #     improvement = (hgs_gap - llm_gap) / llm_gap * 100
        # else:
        #     improvement = float('inf') if hgs_gap > 0 else 0

        # Improvement = (hgs_gap - llm_gap) / hgs_gap * 100%
        if hgs_gap != 0:
            improvement = (hgs_gap - llm_gap) / hgs_gap * 100
        else:
            improvement = float('inf') if llm_gap > 0 else 0
        
        improvements.append(improvement)
        detailed_results.append({
            'instance': instance,
            'hgs_gap': hgs_gap,
            'llm_gap': llm_gap,
            'hgs_time': hgs_time,
            'llm_time': llm_time,
            'improvement_pct': improvement
        })
        
        # Print per-instance detail
        node_count = extract_node_count(instance)
        hgs_time_str = f"{hgs_time:6.1f}s" if hgs_time is not None else "   NA"
        llm_time_str = f"{llm_time:6.1f}s" if llm_time is not None else "   NA"
        print(f"{instance:20} | nodes: {node_count:4d} | HGS: {hgs_gap:8.4f} | LLM: {llm_gap:8.4f} | improv: {improvement:7.2f}% | HGS time: {hgs_time_str} | LLM time: {llm_time_str}")
    
    # Compute statistics
    valid_improvements = [imp for imp in improvements if imp != float('inf')]
    
    if valid_improvements:
        avg_improvement = sum(valid_improvements) / len(valid_improvements)
        min_improvement = min(valid_improvements)
        max_improvement = max(valid_improvements)
        
        print("=" * 80)
        print(f"Summary statistics:")
        print(f"  Avg improvement: {avg_improvement:7.2f}%")
        print(f"  Min improvement: {min_improvement:7.2f}%")
        print(f"  Max improvement: {max_improvement:7.2f}%")
        print(f"  Total instances: {len(common_instances)}")
        print(f"  Valid comparisons: {len(valid_improvements)}")
        
        # Count instances where each method wins
        positive_improvements = [imp for imp in valid_improvements if imp > 0]
        negative_improvements = [imp for imp in valid_improvements if imp < 0]
        
        print(f"  LLM wins: {len(positive_improvements)} ({len(positive_improvements)/len(valid_improvements)*100:.1f}%)")
        print(f"  HGS wins: {len(negative_improvements)} ({len(negative_improvements)/len(valid_improvements)*100:.1f}%)")
    
    # Bucket statistics by node-count range
    print("\n" + "=" * 80)
    print("Breakdown by problem size:")
    print("=" * 80)
    
    # Define bucket ranges
    buckets = [
        (100, 200, "[100, 200)"),
        (200, 400, "[200, 400)"),
        (400, 600, "[400, 600)"),
        (600, 800, "[600, 800)"),
        (800, 1000, "[800, 1000]")
    ]
    
    bucket_stats = {}
    
    for min_nodes, max_nodes, bucket_name in buckets:
        bucket_instances = []
        bucket_improvements = []
        bucket_hgs_gaps = []
        bucket_llm_gaps = []
        bucket_hgs_times = []
        bucket_llm_times = []
        
        for result in detailed_results:
            instance = result['instance']
            node_count = extract_node_count(instance)
            improvement = result['improvement_pct']
            hgs_gap = result['hgs_gap']
            llm_gap = result['llm_gap']
            hgs_time = result['hgs_time']
            llm_time = result['llm_time']
            
            # Handle boundary: [800,1000] is inclusive on both ends
            if bucket_name == "[800, 1000]":
                if min_nodes <= node_count <= max_nodes:
                    bucket_instances.append(instance)
                    if improvement != float('inf'):
                        bucket_improvements.append(improvement)
                    bucket_hgs_gaps.append(hgs_gap)
                    bucket_llm_gaps.append(llm_gap)
                    bucket_hgs_times.append(hgs_time)
                    bucket_llm_times.append(llm_time)
            else:  # upper bound exclusive for other buckets
                if min_nodes <= node_count < max_nodes:
                    bucket_instances.append(instance)
                    if improvement != float('inf'):
                        bucket_improvements.append(improvement)
                    bucket_hgs_gaps.append(hgs_gap)
                    bucket_llm_gaps.append(llm_gap)
                    bucket_hgs_times.append(hgs_time)
                    bucket_llm_times.append(llm_time)
        
        # Bucket statistics
        if bucket_improvements:
            avg_improvement = sum(bucket_improvements) / len(bucket_improvements)
            llm_better = len([imp for imp in bucket_improvements if imp > 0])
            hgs_better = len([imp for imp in bucket_improvements if imp < 0])
        else:
            avg_improvement = 0
            llm_better = 0
            hgs_better = 0
        
        # Average gap and time for this bucket
        avg_hgs_gap = sum(bucket_hgs_gaps) / len(bucket_hgs_gaps) if bucket_hgs_gaps else 0
        avg_llm_gap = sum(bucket_llm_gaps) / len(bucket_llm_gaps) if bucket_llm_gaps else 0
        
        # Average time (skip None values)
        valid_hgs_times = [t for t in bucket_hgs_times if t is not None]
        valid_llm_times = [t for t in bucket_llm_times if t is not None]
        avg_hgs_time = sum(valid_hgs_times) / len(valid_hgs_times) if valid_hgs_times else None
        avg_llm_time = sum(valid_llm_times) / len(valid_llm_times) if valid_llm_times else None
        
        bucket_stats[bucket_name] = {
            'instances': bucket_instances,
            'count': len(bucket_instances),
            'avg_improvement': avg_improvement,
            'llm_better': llm_better,
            'hgs_better': hgs_better,
            'avg_hgs_gap': avg_hgs_gap,
            'avg_llm_gap': avg_llm_gap,
            'avg_hgs_time': avg_hgs_time,
            'avg_llm_time': avg_llm_time
        }
        
        # Print bucket result
        print(f"\n{bucket_name}:")
        print(f"  Instances: {len(bucket_instances)}")
        print(f"  Avg HGS gap: {avg_hgs_gap:7.4f}")
        print(f"  Avg LLM gap: {avg_llm_gap:7.4f}")
        print(f"  Avg improvement: {avg_improvement:7.2f}%")
        hgs_time_str = f"{avg_hgs_time:7.1f}s" if avg_hgs_time is not None else "     NA"
        llm_time_str = f"{avg_llm_time:7.1f}s" if avg_llm_time is not None else "     NA"
        print(f"  Avg HGS time: {hgs_time_str}")
        print(f"  Avg LLM time: {llm_time_str}")
        print(f"  LLM wins: {llm_better}, HGS wins: {hgs_better}")
        print(f"  Instances: {', '.join(bucket_instances[:5])}{'...' if len(bucket_instances) > 5 else ''}")
    
    # Summary report
    print("\n" + "=" * 80)
    print("📊 Performance Analysis Summary")
    print("=" * 80)
    
    print(f"\n📈 Overall statistics:")
    print(f"  • Total instances: {len(common_instances)}")
    print(f"  • Avg improvement: {avg_improvement:.2f}%")
    print(f"  • LLM wins: {len(positive_improvements)} ({len(positive_improvements)/len(valid_improvements)*100:.1f}%)")
    print(f"  • HGS wins: {len(negative_improvements)} ({len(negative_improvements)/len(valid_improvements)*100:.1f}%)")
    print(f"  • Min improvement: {min_improvement:.2f}%")
    print(f"  • Max improvement: {max_improvement:.2f}%")
    
    print(f"\n📋 Breakdown by problem size:")
    print("┌─────────────┬──────────┬──────────┬──────────┬──────────┬──────────┐")
    print("│ Node range  │ Count    │ Avg HGS  │ Avg LLM  │ Avg HGS  │ Avg LLM  │")
    print("│             │          │ gap      │ gap      │ time(s)  │ time(s)  │")
    print("├─────────────┼──────────┼──────────┼──────────┼──────────┼──────────┤")
    
    for bucket_name, stats in bucket_stats.items():
        avg_hgs_gap = stats['avg_hgs_gap']
        avg_llm_gap = stats['avg_llm_gap']
        avg_hgs_time = stats['avg_hgs_time']
        avg_llm_time = stats['avg_llm_time']
        count = stats['count']
        
        hgs_time_str = f"{avg_hgs_time:8.1f}" if avg_hgs_time is not None else "      NA"
        llm_time_str = f"{avg_llm_time:8.1f}" if avg_llm_time is not None else "      NA"
        
        print(f"│ {bucket_name:11} │ {count:8} │ {avg_hgs_gap:8.4f} │ {avg_llm_gap:8.4f} │ {hgs_time_str} │ {llm_time_str} │")
    
    print("└─────────────┴──────────┴──────────┴──────────┴──────────┴──────────┘")
    
    # Determine advantage range for each method
    small_scale = bucket_stats.get("[100, 200)", {})
    medium_scale_1 = bucket_stats.get("[200, 400)", {})
    medium_scale_2 = bucket_stats.get("[400, 600)", {})
    large_scale_1 = bucket_stats.get("[600, 800)", {})
    large_scale_2 = bucket_stats.get("[800, 1000]", {})
    
    # Average improvement for medium-scale problems
    if medium_scale_1 and medium_scale_2:
        medium_avg = (medium_scale_1['avg_improvement'] + medium_scale_2['avg_improvement']) / 2
    else:
        medium_avg = 0
    
    # Average improvement for large-scale problems
    if large_scale_1 and large_scale_2:
        large_avg = (large_scale_1['avg_improvement'] + large_scale_2['avg_improvement']) / 2
    else:
        large_avg = 0
    
    print(f"\n🔍 Key insights:")
    print(f"  • LLM advantage range: 200-600 nodes, avg improvement ≈{medium_avg:.2f}%")
    print(f"  • HGS advantage range: 100-200 nodes, avg improvement {small_scale.get('avg_improvement', 0):.2f}%")
    print(f"  • Balanced range: 600-1000 nodes, methods comparable, avg improvement {large_avg:.2f}%")
    
    print(f"\n💡 Practical recommendations:")
    
    # Generate recommendations from actual data
    if small_scale.get('hgs_better', 0) > small_scale.get('llm_better', 0):
        print(f"  • Small instances (<200 nodes): HGS recommended (HGS wins: {small_scale.get('hgs_better', 0)}, LLM wins: {small_scale.get('llm_better', 0)})")
    else:
        print(f"  • Small instances (<200 nodes): LLM recommended (LLM wins: {small_scale.get('llm_better', 0)}, HGS wins: {small_scale.get('hgs_better', 0)})")
    
    if medium_avg > 5:
        print(f"  • Medium instances (200-600 nodes): LLM recommended (avg improvement {medium_avg:.2f}%)")
    else:
        print(f"  • Medium instances (200-600 nodes): both methods viable (avg improvement {medium_avg:.2f}%)")
    
    if abs(large_avg) < 3:
        print(f"  • Large instances (>600 nodes): both methods viable (avg improvement {large_avg:.2f}%)")
    elif large_avg > 0:
        print(f"  • Large instances (>600 nodes): LLM recommended (avg improvement {large_avg:.2f}%)")
    else:
        print(f"  • Large instances (>600 nodes): HGS recommended (avg improvement {large_avg:.2f}%)")
    
    print(f"\n" + "=" * 80)
    print("📝 Data sources:")
    print(f"  • HGS result file: {hgs_file}")
    print(f"  • LLM result file: {llm_file}")
    print(f"  • Analysis script: compare_json_gaps.py")
    print("=" * 80)

def show_help():
    """Display detailed help text."""
    help_text = """
🔍 CVRP Performance Comparison Tool - Help
=====================================

📖 Description:
   Compare performance of the HGS algorithm and LLM-generated operators on CVRP.
   Computes per-instance and aggregate improvement of LLM over HGS based on optimality gap.

🚀 Usage:
   python compare_json_gaps.py <llm_results.json> <hgs_results.json>
   
   Or show help:
   python compare_json_gaps.py --help
   python compare_json_gaps.py -h

📁 File requirements:
   • LLM result file: JSON file produced by vllm_evaluate.py
   • HGS baseline file: JSON file produced by the HGS baseline run
   
   Expected JSON structure:
   {
     "all_costs": [
       {
         "instance_name": "X-n101-k25",
         "gap": 0.13772607009532095,
         "cost": 27629
       },
       ...
     ]
   }

📊 Output:
   1. Per-instance comparison table (sorted by node count, descending)
   2. Overall statistics summary
   3. Breakdown by problem-size bucket
   4. Performance analysis report
   5. Practical recommendations

🔢 Formula:
   Improvement (%) = (HGS_gap - LLM_gap) / HGS_gap × 100%

   Positive value → LLM is better; negative value → HGS is better

📈 Buckets:
   • [100, 200): small
   • [200, 400): medium (lower half)
   • [400, 600): medium (upper half)
   • [600, 800): large (lower half)
   • [800, 1000]: large (upper half)

💡 Examples:
   # Basic usage
   python compare_json_gaps.py llm_gap.json hgs_gap.json
   
   # Compare different result files
   python compare_json_gaps.py my_llm_results.json my_hgs_results.json
   
   # Show help
   python compare_json_gaps.py --help

⚠️  Notes:
   • Two arguments are required: LLM result file and HGS baseline file
   • Both JSON files must contain an 'all_costs' field
   • Instance names must follow the format 'X-n{nodes}-k{vehicles}'
   • Ensure your terminal supports UTF-8

🛠️  Troubleshooting:
   • "File not found": check the file paths
   • "Not a valid JSON file": check JSON syntax
   • "'all_costs' field not found": check the JSON structure

📞 Support:
   If you encounter issues, verify:
   1. Python version (3.6+)
   2. File permissions
   3. JSON file format
   4. Instance name format

=====================================
    """
    print(help_text)

def main():
    """Main entry point."""
    # Check for help flag
    if len(sys.argv) == 2 and sys.argv[1] in ['--help', '-h', 'help']:
        show_help()
        return
    
    # Validate argument count
    if len(sys.argv) != 3:
        print("❌ Usage error!")
        print("\n📖 Usage:")
        print("   python compare_json_gaps.py <llm_results.json> <hgs_results.json>")
        print("   python compare_json_gaps.py --help  # show detailed help")
        print("\n💡 Note:")
        print("   • Two arguments required: LLM result file and HGS baseline file")
        print("   • Both arguments are mandatory; there are no defaults")
        print("\n🔍 Need help? Run: python compare_json_gaps.py --help")
        sys.exit(1)
    
    llm_file = sys.argv[1]
    hgs_file = sys.argv[2]
    
    # Validate that files exist
    import os
    if not os.path.exists(hgs_file):
        print(f"❌ Error: HGS baseline file not found: {hgs_file}")
        print("Please check the file path.")
        print("\n🔍 Need help? Run: python compare_json_gaps.py --help")
        sys.exit(1)
    
    if not os.path.exists(llm_file):
        print(f"❌ Error: LLM result file not found: {llm_file}")
        print("Please check the file path.")
        print("\n🔍 Need help? Run: python compare_json_gaps.py --help")
        sys.exit(1)
    
    print("🚀 Starting comparison analysis...")
    print(f"📊 HGS baseline file: {hgs_file}")
    print(f"📊 LLM result file:   {llm_file}")
    print("=" * 60)
    
    compare_gaps(hgs_file, llm_file)

